changeSet.sql:
CREATE TABLE candidate_resume_language ( id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, candidate_resume_id BIGINT NOT NULL, language VARCHAR(255) NOT NULL, level VARCHAR(32) NOT NULL, sort_order INTEGER, CONSTRAINT fk_candidate_resume_language_resume FOREIGN KEY (candidate_resume_id) REFERENCES candidate_resume(id) );
CREATE TABLE candidate_resume_education ( id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, candidate_resume_id BIGINT NOT NULL, institution VARCHAR(255) NOT NULL, specialty VARCHAR(255) NOT NULL, education_level VARCHAR(255) NOT NULL, start_date DATE NOT NULL, end_date DATE, currently_studying BOOLEAN NOT NULL DEFAULT FALSE, sort_order INTEGER, CONSTRAINT fk_candidate_resume_education_resume FOREIGN KEY (candidate_resume_id) REFERENCES candidate_resume(id) );
CREATE TABLE candidate_resume_work_experience ( id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, candidate_resume_id BIGINT NOT NULL, company VARCHAR(255) NOT NULL, position_name VARCHAR(255) NOT NULL, work_format_id VARCHAR(255) NOT NULL, start_date DATE NOT NULL, end_date DATE, currently_working BOOLEAN NOT NULL DEFAULT FALSE, project_url VARCHAR(255), sort_order INTEGER, CONSTRAINT fk_candidate_resume_work_experience_resume FOREIGN KEY (candidate_resume_id) REFERENCES candidate_resume(id), CONSTRAINT fk_candidate_resume_work_experience_work_format FOREIGN KEY (work_format_id) REFERENCES work_format(id) );
CREATE INDEX idx_candidate_resume_language_resume_id ON candidate_resume_language(candidate_resume_id);
CREATE INDEX idx_candidate_resume_education_resume_id ON candidate_resume_education(candidate_resume_id);
CREATE INDEX idx_candidate_resume_work_experience_resume_id ON candidate_resume_work_experience(candidate_resume_id);

CREATE TABLE language_dictionary ( id VARCHAR(64) NOT NULL PRIMARY KEY, name VARCHAR(128) NOT NULL UNIQUE );
INSERT INTO language_dictionary(id, name) VALUES ('arabic', 'Арабский'), ('armenian', 'Армянский'), ('azerbaijani', 'Азербайджанский'), ('belarusian', 'Белорусский'), ('bengali', 'Бенгальский'), ('bulgarian', 'Болгарский'), ('chinese', 'Китайский'), ('croatian', 'Хорватский'), ('czech', 'Чешский'), ('danish', 'Датский'), ('dutch', 'Нидерландский'), ('english', 'Английский'), ('estonian', 'Эстонский'), ('finnish', 'Финский'), ('french', 'Французский'), ('georgian', 'Грузинский'), ('german', 'Немецкий'), ('greek', 'Греческий'), ('hebrew', 'Иврит'), ('hindi', 'Хинди'), ('hungarian', 'Венгерский'), ('indonesian', 'Индонезийский'), ('italian', 'Итальянский'), ('japanese', 'Японский'), ('kazakh', 'Казахский'), ('korean', 'Корейский'), ('kyrgyz', 'Киргизский'), ('latvian', 'Латышский'), ('lithuanian', 'Литовский'), ('malay', 'Малайский'), ('mongolian', 'Монгольский'), ('norwegian', 'Норвежский'), ('persian', 'Персидский'), ('polish', 'Польский'), ('portuguese', 'Португальский'), ('punjabi', 'Панджаби'), ('romanian', 'Румынский'), ('russian', 'Русский'), ('serbian', 'Сербский'), ('slovak', 'Словацкий'), ('spanish', 'Испанский'), ('swedish', 'Шведский'), ('tagalog', 'Тагальский'), ('tajik', 'Таджикский'), ('thai', 'Тайский'), ('turkish', 'Турецкий'), ('turkmen', 'Туркменский'), ('ukrainian', 'Украинский'), ('urdu', 'Урду'), ('uzbek', 'Узбекский'), ('vietnamese', 'Вьетнамский') ON CONFLICT (id) DO NOTHING;
ALTER TABLE candidate_resume_language ADD COLUMN language_id VARCHAR(64);
UPDATE candidate_resume_language crl SET language_id = COALESCE( ( SELECT ld.id FROM language_dictionary ld WHERE LOWER(ld.name) = LOWER(crl.language) LIMIT 1 ), 'english' ) WHERE crl.language_id IS NULL;
ALTER TABLE candidate_resume_language ALTER COLUMN language_id SET NOT NULL;
ALTER TABLE candidate_resume_language DROP COLUMN language;
ALTER TABLE candidate_resume_language ADD CONSTRAINT fk_candidate_resume_language_dictionary FOREIGN KEY (language_id) REFERENCES language_dictionary(id);
CREATE INDEX idx_candidate_resume_language_language_id ON candidate_resume_language(language_id);
